class Solution:
    def minMergeCost(self, lists):
        n = len(lists)
        full = 1 << n
        length = [0] * full
        median = [0] * full
        for mask in range(1, full):
            arr = []
            for i in range(n):
                if mask & (1 << i):
                    arr.extend(lists[i])
            arr.sort()
            length[mask] = len(arr)
            median[mask] = arr[(len(arr) - 1) // 2]
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(mask):
            if mask & (mask - 1) == 0:
                return 0
            best = None
            sub = (mask - 1) & mask
            while sub > 0:
                other = mask ^ sub
                if sub < other:
                    c = dp(sub) + dp(other) + length[sub] + length[other] + abs(median[sub] - median[other])
                    if best is None or c < best:
                        best = c
                sub = (sub - 1) & mask
            return best
        result = dp(full - 1)
        dp.cache_clear()
        return result

