class Solution:
    def minMergeCost(self, lists) -> int:
        n = len(lists)
        full = 1 << n
        merged = [None] * full
        length = [0] * full
        median = [0] * full
        for i in range(n):
            bit = 1 << i
            merged[bit] = lists[i]
            length[bit] = len(lists[i])
            median[bit] = lists[i][(len(lists[i]) - 1) // 2]
        for mask in range(1, full):
            if merged[mask] is not None:
                continue
            low = mask & (-mask)
            rest = mask ^ low
            a = merged[low]
            b = merged[rest]
            i = j = 0
            out = []
            la, lb = len(a), len(b)
            while i < la and j < lb:
                if a[i] <= b[j]:
                    out.append(a[i]); i += 1
                else:
                    out.append(b[j]); j += 1
            if i < la:
                out.extend(a[i:])
            if j < lb:
                out.extend(b[j:])
            merged[mask] = out
            length[mask] = len(out)
            median[mask] = out[(len(out) - 1) // 2]
        dp = [0] * full
        for mask in range(1, full):
            if mask & (mask - 1) == 0:
                continue
            best = None
            sub = (mask - 1) & mask
            while sub > 0:
                other = mask ^ sub
                if sub < other:
                    cost = dp[sub] + dp[other] + length[sub] + length[other] + abs(median[sub] - median[other])
                    if best is None or cost < best:
                        best = cost
                sub = (sub - 1) & mask
            dp[mask] = best
        return dp[full - 1]

