var minMergeCost = function(lists) {
    const n = lists.length;
    const full = 1 << n;
    const merged = new Array(full).fill(null);
    const length = new Array(full).fill(0);
    const median = new Array(full).fill(0);
    for (let i = 0; i < n; i++) {
        const bit = 1 << i;
        merged[bit] = lists[i];
        length[bit] = lists[i].length;
        median[bit] = lists[i][Math.floor((lists[i].length - 1) / 2)];
    }
    for (let mask = 1; mask < full; mask++) {
        if (merged[mask] !== null) continue;
        const low = mask & (-mask);
        const rest = mask ^ low;
        const a = merged[low];
        const b = merged[rest];
        let i = 0, j = 0;
        const out = [];
        while (i < a.length && j < b.length) {
            if (a[i] <= b[j]) out.push(a[i++]);
            else out.push(b[j++]);
        }
        while (i < a.length) out.push(a[i++]);
        while (j < b.length) out.push(b[j++]);
        merged[mask] = out;
        length[mask] = out.length;
        median[mask] = out[Math.floor((out.length - 1) / 2)];
    }
    const dp = new Array(full).fill(0);
    for (let mask = 1; mask < full; mask++) {
        if ((mask & (mask - 1)) === 0) continue;
        let best = null;
        let sub = (mask - 1) & mask;
        while (sub > 0) {
            const other = mask ^ sub;
            if (sub < other) {
                const cost = dp[sub] + dp[other] + length[sub] + length[other] + Math.abs(median[sub] - median[other]);
                if (best === null || cost < best) best = cost;
            }
            sub = (sub - 1) & mask;
        }
        dp[mask] = best;
    }
    return dp[full - 1];
};
